def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 1, -1):
                for b in range(2, a + 4):
                    term1 = np.exp(-(ratio - a) ** 2) * np.sin(ratio * b / (a + 0.5))
                    for c in range(1, b):
                        term1 += np.tanh((ratio / (c + 0.1)) ** 3) * np.cos(c * ratio / (a + 1))
                    priority += term1 / (a * b + 1)
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
        elif 4 < ratio <= 7:
            acc = 0
            for x in range(1, int(np.ceil(ratio)) + 5):
                inner_sum = 0
                for y in range(1, x + 3):
                    val = ((ratio - x) ** 4) * np.sin(ratio * y) / (y + 0.7)
                    inner_sum += np.tanh(val) * np.exp(-y / (x + 1))
                acc += inner_sum
            priority = acc * 1.3 + np.log(ratio + 1) * 12 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s1, s2 = 0, 0
            for r in range(1, 14):
                s1 += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.2)
                if r % 2 == 0:
                    s2 += np.sin(r * ratio) / (r + 0.5)
            priority = (s1 * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            priority += s2 * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (np.sqrt(n) + 0.4) * np.sin(n * ratio * 2.1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.75)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.03))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1) ** m) / m
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * item * 1.3)
            priority = s
            if (i * int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 14):
                s += ((0.4 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.5)
            priority = s + 2 / (bin_cap + 4.5)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 2.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap + 1) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.8
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.3
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap + 2) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.2
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.5 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.35
                priority += np.cos(ratio * idx * i) * 0.25
            else:
                priority -= np.cos(ratio * (i + idx ** 2)) * 0.35
                priority -= np.sin(ratio * idx * i * 1.1) * 0.25
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
            priority += np.tanh(ratio / (i + 1)) * 0.5
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
            priority -= np.tanh(ratio * (i + 2)) * 0.5
        if i % 7 == 0:
            for w in range(1, 5):
                priority += np.sin(ratio * w * i / 2) * 0.1
        else:
            for w in range(1, 5):
                priority -= np.cos(ratio * w * i / 3) * 0.1
        priorities[i] = priority
    return priorities
